//! `ffs overview` — high-signal summary of the workspace for agents.

use std::collections::{BTreeMap, HashMap};
use std::path::Path;
use std::time::SystemTime;

use anyhow::Result;
use clap::Parser;
use serde::Serialize;

use ffs_engine::Engine;
